背包-模板题 #参考：背包九讲——全篇详细理解与代码实现
1. 01背包 #例题采药
#include &lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); using namespace std; typedef long long ll; const int maxn = 10000007; const ll inf = 0x3f3f3f3f; ll v[maxn], w[maxn], dp[maxn]; ll n, m; //P1048 01背包 int main() { ios; cin &gt;&gt; m &gt;&gt; n; for (int i = 1; i &lt;= n; i++) { cin &gt;&gt; w[i] &gt;&gt; v[i]; } for (int i = 1; i &lt;= n; i++) { for (int j = m; j &gt;= w[i]; j--) { dp[j] = max(dp[j], dp[j - w[i]] + v[i]); } } cout &lt;&lt; dp[m] &lt;&lt; endl; return 0; } 2.完全背包 #例题：P1853 投资的最大效益
#include&lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl #define inr register int using namespace std; typedef long long ll; const double pi=acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 10000007;//1e5+7 const ll mod = 1000000007;//1e9+7 ll dp[maxn]; ll w[maxn]; ll v[maxn]; int main() { ll s; int n,d; cin&gt;&gt;s&gt;&gt;n&gt;&gt;d; for(int i = 1;i&lt;=d;i++){ cin&gt;&gt;w[i]&gt;&gt;v[i]; } ll nw = s,sx; for(int ye = 1;ye&lt;=n;ye++){ sx = nw; for(int i = 1;i&lt;=d;i++){ for(int j = w[i];j&lt;=sx;j++){ dp[j] = max(dp[j],dp[j - w[i]] + v[i]); } } nw += dp[sx]; } cout&lt;&lt;nw&lt;&lt;endl; return 0; } 例题2：P1616 疯狂的采药 先物品后容积
#include&lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl #define inr register int using namespace std; typedef long long ll; const double pi=acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 10000007;//1e5+7 const ll mod = 1000000007;//1e9+7 ll dp[maxn]; int main() { ll n,m; cin&gt;&gt;n&gt;&gt;m; for(ll i = 1,w,v;i&lt;=m;i++){ cin&gt;&gt;w&gt;&gt;v; for(ll j = w;j&lt;=n;j++){ dp[j] = max(dp[j],dp[j - w] + v); } } cout&lt;&lt;dp[n]&lt;&lt;endl; return 0; } 3.多重背包 #例题：P1776 宝物筛选
转化为01背包问题求解 #既然01背包问题是最基本的背包问题，那么我们可以考虑把完全背包问题转化为01背包问题来解。思路：将多种物品用二进制的思想合并。
#include&lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl #define inr register int using namespace std; typedef long long ll; const double pi=acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 10000007;//1e5+7 const ll mod = 1000000007;//1e9+7 ll dp[maxn]; ll w[maxn]; ll v[maxn]; int main() { ll s; int n,d; cin&gt;&gt;s&gt;&gt;n&gt;&gt;d; for(int i = 1;i&lt;=d;i++){ cin&gt;&gt;w[i]&gt;&gt;v[i]; } ll nw = s,sx; for(int ye = 1;ye&lt;=n;ye++){ sx = nw; for(int i = 1;i&lt;=d;i++){ for(int j = w[i];j&lt;=sx;j++){ dp[j] = max(dp[j],dp[j - w[i]] + v[i]); } } nw += dp[sx]; } cout&lt;&lt;nw&lt;&lt;endl; return 0; } &#34; ```cpp #include&lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl #define inr register int using namespace std; typedef long long ll; const double pi=acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 100007;//1e5+7 const ll mod = 1000000007;//1e9+7 ll w[maxn]; ll v[maxn]; ll tw[maxn]; ll tv[maxn]; ll s[maxn]; ll ksm(ll x,ll y) { ll res = 1; while(y &gt; 0){ if(y&amp;1){ res = res * x; } y &gt;&gt;= 1; x = x * x; } return res; } ll dp[maxn]; int main() { int n; ll W; cin&gt;&gt;n&gt;&gt;W; for(int i = 1;i&lt;=n;i++){ cin&gt;&gt;tv[i]&gt;&gt;tw[i]&gt;&gt;s[i]; } int m = 0; for(int i = 1;i&lt;=n;i++){ ll mxs = W / s[i]; ll zs = 0; while(s[i] &gt; 0){ ll nw = ksm(2,zs); if(s[i] &gt;= nw){ s[i] -= nw; w[++m] = tw[i] * nw; v[m] = tv[i] * nw; } else{ w[++m] = tw[i] * s[i]; v[m] = tv[i] * s[i]; s[i] = 0; } zs++; } } for(int i = 1;i&lt;=m;i++){ for(int j = W;j&gt;=w[i];j--){ dp[j] = max(dp[j],dp[j - w[i]] + v[i]); } } cout&lt;&lt;dp[W]&lt;&lt;endl; return 0; } 4.混合背包 #例题：P1833 樱花 分类讨论 + 降维打击：完全型物品完全解法，01型物品、多重型物品，降维成01背包解决
#include&lt;bits/stdc++.h&gt; #define ios::sync_with_stdio(false);cin.tie(0);cout.tie(0) using namespace std; const int maxn = 1000007; int dp[maxn]; bool inf[maxn]; int w[maxn]; int v[maxn]; int main() { int sh,sm,eh,em,n,m = 0; scanf(&#34;%d:%d %d:%d %d&#34;,&amp;sh,&amp;sm,&amp;eh,&amp;em,&amp;n); int T = (eh - sh) * 60 + em - sm ; //cout&lt;&lt;T&lt;&lt;endl; memset(dp,0,sizeof(dp)); memset(inf,0,sizeof(inf)); for(int i = 1,tw,tv,s;i&lt;=n;i++){ cin&gt;&gt;tw&gt;&gt;tv&gt;&gt;s; if(s == 0){ w[++m] = tw; v[m] = tv; inf[m] = 1; } else{ for(int j = 1;j&lt;=s;j&lt;&lt;=1){ w[++m] = tw * j; v[m] = tv * j; s -= j; } if(s){ w[++m] = tw * s; v[m] = tv * s; } } } for(int i = 1;i&lt;=m;i++){ if(inf[i]){ for(int j = w[i];j&lt;=T;j++){ dp[j] = max(dp[j],dp[j - w[i]] + v[i]); } } else{ for(int j = T;j&gt;=w[i];j--){ dp[j] = max(dp[j],dp[j - w[i]] + v[i]); } } } cout&lt;&lt;dp[T]&lt;&lt;endl; return 0; } 5.二维费用背包 #例题：P1507 NASA的食物计划 在普通背包的基础上多加了一维费用而已
#include&lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl #define inr register int using namespace std; typedef long long ll; const double pi=acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 1007;//1e5+7 const ll mod = 1000000007;//1e9+7 int dp[maxn][maxn]; int main() { int T,W,n; cin&gt;&gt;T&gt;&gt;W; cin&gt;&gt;n; for(int i = 1,t,w,v;i&lt;=n;i++){ cin&gt;&gt;t&gt;&gt;w&gt;&gt;v; for(int j = W;j&gt;=w;j--){ for(int k = T;k&gt;=t;k--){ dp[j][k] = max(dp[j][k],dp[j - w][k - t] + v); } } } cout&lt;&lt;dp[W][T]&lt;&lt;endl; return 0; } 6.分组背包 #例题：P1757 通天之分组背包
以前的01物品变成了一个个的物品组，做法别无二致，在循环的内部多一重对组内物品的枚举即可
for (所有的组k) for (int j = V; j &gt;= 0; j--) for (所有属于组k的i) f[j] = max{f[j], f[j - w[i]] + v[i]} #include&lt;bits/stdc++.h&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl #define inr register int using namespace std; typedef long long ll; const double pi=acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 100007;//1e5+7 const ll mod = 1000000007;//1e9+7 int dp[maxn]; struct node{ int w,v; }; vector&lt;node&gt;G[maxn]; int main() { int n,m,mx = 0; cin&gt;&gt;m&gt;&gt;n; for(int i = 1,a,b,c;i&lt;=n;i++){ cin&gt;&gt;a&gt;&gt;b&gt;&gt;c; node nd; nd.w = a; nd.v = b; mx = max(c,mx); G[c].push_back(nd); } for(int i = 0;i&lt;=mx;i++){ if(G[i].size()){ for(int j = m;j&gt;=0;j--){ for(int k = 0;k&lt;=G[i].size();k++){ if(G[i][k].w &lt;= j){ dp[j] = max(dp[j],dp[j - G[i][k].w] + G[i][k].v); } } }	} } cout&lt;&lt;dp[m]&lt;&lt;endl; return 0; } 7.有依赖的背包 #例题：P1064 金明的预算方案
#include &lt;iostream&gt; #include &lt;fstream&gt; #include &lt;cstdio&gt; #include &lt;cmath&gt; #include &lt;algorithm&gt; #include &lt;cstring&gt; #include &lt;queue&gt; #include &lt;stack&gt; #include &lt;vector&gt; #include &lt;map&gt; #include &lt;set&gt; #define ios ios::sync_with_stdio(false);cin.tie(0);cout.tie(0); #define debug(a) cout &lt;&lt; #a &lt;&lt; &#34; &#34; &lt;&lt; a &lt;&lt; endl using namespace std; typedef long long ll; const double pi = acos(-1); const double eps = 1e-8; const int inf = 0x3f3f3f3f; const int maxn = 67; const int maxm = 50007;//5e4+7 const ll mod = 1000000007;//1e9+7 int read() { int res = 0, ch, flag = 0; if ((ch = getchar()) == &#39;-&#39;) flag = 1; else if (ch &gt;= &#39;0&#39; &amp;&amp; ch &lt;= &#39;9&#39;) res = ch - &#39;0&#39;; while ((ch = getchar()) &gt;= &#39;0&#39; &amp;&amp; ch &lt;= &#39;9&#39;) res = res * 10 + ch - &#39;0&#39;; return flag ? -res : res; } int n, m; struct node { int w, v; }; vector&lt;node&gt;G[maxn]; node zj[maxn]; int pdp[maxn][maxm]; int dp[maxm]; bool pd[maxn]; int main() { n = read(); m = read(); n /= 10; for (int i = 1,q, w, v; i &lt;= m; i++) { w = read();v = read();q = read(); w /= 10; if (q) { G[q].push_back(node{ w,v * w }); } else { pd[i] = 1; zj[i] = node{ w,v * w }; } } for (int i = 1; i &lt;= m; i++) { if (pd[i]) { for (int j = zj[i].w; j &lt;= n; j++) { pdp[i][j] = zj[i].v; } for (int j = 0; j &lt; G[i].size(); j++) { for (int k = n; k &gt;= G[i][j].w + zj[i].w; k--) { pdp[i][k] = max(pdp[i][k], pdp[i][k - G[i][j].w] + G[i][j].v); } } } } for (int i = 1; i &lt;= m; i++) { if (pd[i]) { for (int j = n; j &gt;= 0;j--) { for (int k = zj[i].w; k &lt;= j; k++) { dp[j] = max(dp[j], dp[j - k] + pdp[i][k]); } } } } printf(&#34;%d\n&#34;,dp[n] * 10); return 0; } 总结 #总结：不论背包问题多么复杂，皆可向01背包的思路靠近
